/** 소분류 코드로 전체 경로 조회 */
export const getCategoryPath = (smallCode: string): string => {
  const item = CATEGORY_FLAT.find(c => c.smallCode === smallCode);
  return item ? item.path : '';
};

/** 소분류 코드로 CategoryFlat 조회 */
export const getCategoryByCode = (smallCode: string): CategoryFlat | undefined =>
  CATEGORY_FLAT.find(c => c.smallCode === smallCode);

